import{_ as o}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as a,o as d,X as c}from"./chunks/vendor-vueuse.XPft87tp.js";const S=JSON.parse('{"title":"ES 每个版本引入了什么内容","description":"","frontmatter":{},"headers":[],"relativePath":"basics/es-version-history.md","filePath":"basics/es-version-history.md","lastUpdated":1784884957000}'),t={name:"basics/es-version-history.md"};function r(i,e,s,l,n,h){return d(),a("div",null,e[0]||(e[0]=[c('<h1 id="es-每个版本引入了什么内容" tabindex="-1">ES 每个版本引入了什么内容 <a class="header-anchor" href="#es-每个版本引入了什么内容" aria-label="Permalink to &quot;ES 每个版本引入了什么内容&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>ES5、ES6、ES2016……每年 TC39 都往 JavaScript 里塞新东西。记住每个版本加了什么，面试经常考，平时看源码也能更快理解别人用了什么新语法。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="es5-2009" tabindex="-1">ES5 (2009) <a class="header-anchor" href="#es5-2009" aria-label="Permalink to &quot;ES5 (2009)&quot;">​</a></h3><p>严格模式 <code>&quot;use strict&quot;</code> 是这版加的，还有 <code>Object.defineProperty</code>、<code>Array.prototype.forEach/map/filter/reduce</code>、<code>JSON.parse/stringify</code>。基本上就是让 JS 从不正经变得稍微正经了点。</p><h3 id="es6-es2015" tabindex="-1">ES6 / ES2015 <a class="header-anchor" href="#es6-es2015" aria-label="Permalink to &quot;ES6 / ES2015&quot;">​</a></h3><p>这是 JavaScript 历史上最大的一次更新，几乎重新定义了这门语言：</p><ul><li><code>let</code>、<code>const</code>（块级作用域）</li><li>箭头函数 <code>() =&gt; {}</code></li><li>模板字符串 <code>\\</code>hello ${name}``</li><li>解构赋值 <code>const { a, b } = obj</code></li><li>Promise、<code>class</code>、<code>import/export</code> 模块</li><li><code>Map</code>、<code>Set</code>、<code>Symbol</code>、<code>for...of</code></li><li>展开运算符 <code>...</code>、默认参数</li></ul><p>基本上现在写 JS 绕不开的东西，全是 ES6 的。</p><h3 id="es2017" tabindex="-1">ES2017 <a class="header-anchor" href="#es2017" aria-label="Permalink to &quot;ES2017&quot;">​</a></h3><p><code>async/await</code> 登场，Promise 链终于不用写得跟面条似的了。<code>Object.values/entries</code> 也在这版。</p><h3 id="es2018" tabindex="-1">ES2018 <a class="header-anchor" href="#es2018" aria-label="Permalink to &quot;ES2018&quot;">​</a></h3><p><code>Promise.finally</code>、异步迭代 <code>for-await-of</code>、对象展开运算符 <code>{...obj}</code>。</p><h3 id="es2020" tabindex="-1">ES2020 <a class="header-anchor" href="#es2020" aria-label="Permalink to &quot;ES2020&quot;">​</a></h3><p>可选链 <code>?.</code> 和空值合并 <code>??</code>——这两个简直救了多少人于 <code>Cannot read property of undefined</code> 的水深火热之中。还有 BigInt、<code>Promise.allSettled</code>。</p><h3 id="es2021" tabindex="-1">ES2021+ <a class="header-anchor" href="#es2021" aria-label="Permalink to &quot;ES2021+&quot;">​</a></h3><p>逻辑赋值 <code>||=</code> <code>&amp;&amp;=</code> <code>??=</code>、<code>replaceAll</code>、<code>at()</code>（负数索引）。后面每年的更新都比较小，这里不展开了。</p><h2 id="实战场景" tabindex="-1">实战场景 <a class="header-anchor" href="#实战场景" aria-label="Permalink to &quot;实战场景&quot;">​</a></h2><p>面试最常问的两个问题：&quot;ES6 有哪些新特性&quot;和&quot;可选链和空值合并怎么用&quot;。日常开发中 <code>?.</code> 和 <code>??</code> 基本天天用，写出来的代码短了一截还不容易崩。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>ES6 是分水岭，后面每年小步快跑。面试前把 ES6 的几个大特性捋一遍就行。</p>',22)]))}const m=o(t,[["render",r]]);export{S as __pageData,m as default};
